static USBDevice *usb_msd_init(USBBus *bus, const char *filename)

{

    static int nr=0;

    char id[8];

    QemuOpts *opts;

    DriveInfo *dinfo;

    USBDevice *dev;

    const char *p1;

    char fmt[32];



    /* parse -usbdevice disk: syntax into drive opts */

    do {

        snprintf(id, sizeof(id), "usb%d", nr++);

        opts = qemu_opts_create(qemu_find_opts("drive"), id, 1, NULL);

    } while (!opts);



    p1 = strchr(filename, ':');

    if (p1++) {

        const char *p2;



        if (strstart(filename, "format=", &p2)) {

            int len = MIN(p1 - p2, sizeof(fmt));

            pstrcpy(fmt, len, p2);

            qemu_opt_set(opts, "format", fmt);

        } else if (*filename != ':') {

            error_report("unrecognized USB mass-storage option %s", filename);

            return NULL;

        }

        filename = p1;

    }

    if (!*filename) {

        error_report("block device specification needed");

        return NULL;

    }

    qemu_opt_set(opts, "file", filename);

    qemu_opt_set(opts, "if", "none");



    /* create host drive */

    dinfo = drive_new(opts, 0);

    if (!dinfo) {

        qemu_opts_del(opts);

        return NULL;

    }



    /* create guest device */

    dev = usb_create(bus, "usb-storage");

    if (!dev) {

        return NULL;

    }

    if (qdev_prop_set_drive(&dev->qdev, "drive",

                            blk_bs(blk_by_legacy_dinfo(dinfo))) < 0) {

        object_unparent(OBJECT(dev));

        return NULL;

    }

    if (qdev_init(&dev->qdev) < 0)

        return NULL;



    return dev;

}

