            if (flush || av_fifo_size(&sc->audio_buffer) >= GXF_AUDIO_PACKET_SIZE) {

                if (!pkt && gxf_new_audio_packet(gxf, sc, &new_pkt, flush) > 0) {

                    pkt = &new_pkt;

                    break; /* add pkt right now into list */

                }

            }

        }

    }

    return av_interleave_packet_per_dts(s, out, pkt, flush);

}

