            ret = USB_RET_STALL;

            break;

        }

    } else {

        /* data pipe */

        ret = usb_device_handle_data(dev, p);

    }



    if (ret == USB_RET_ASYNC) {

        p->owner = usb_ep_get(dev, p->pid, p->devep);

    }

    return ret;

}

