GuestFileWrite *qmp_guest_file_write(int64_t handle, const char *buf_b64,

                                     bool has_count, int64_t count,

                                     Error **errp)

{

    GuestFileWrite *write_data = NULL;

    guchar *buf;

    gsize buf_len;

    int write_count;

    GuestFileHandle *gfh = guest_file_handle_find(handle, errp);

    FILE *fh;



