AUDIT
int load_aout(const char *filename, target_phys_addr_t addr, int max_sz,

              int bswap_needed, target_phys_addr_t target_page_size)

{

    int fd, size, ret;

    struct exec e;

    uint32_t magic;



    fd = open(filename, O_RDONLY | O_BINARY);

    if (fd < 0)

        return -1;



    size = read(fd, &e, sizeof(e));

    if (size < 0)

        goto fail;



    if (bswap_needed) {

        bswap_ahdr(&e);

    }



    magic = N_MAGIC(e);

    switch (magic) {

    case ZMAGIC:

    case QMAGIC:

    case OMAGIC:

        if (e.a_text + e.a_data > max_sz)

            goto fail;

	lseek(fd, N_TXTOFF(e), SEEK_SET);

	size = read_targphys(filename, fd, addr, e.a_text + e.a_data);

	if (size < 0)

	    goto fail;

	break;

    case NMAGIC:

        if (N_DATADDR(e, target_page_size) + e.a_data > max_sz)

            goto fail;

	lseek(fd, N_TXTOFF(e), SEEK_SET);

	size = read_targphys(filename, fd, addr, e.a_text);

	if (size < 0)

	    goto fail;

        ret = read_targphys(filename, fd, addr + N_DATADDR(e, target_page_size),

                            e.a_data);

	if (ret < 0)

	    goto fail;

	size += ret;

	break;

    default:

	goto fail;

    }

    close(fd);

    return size;

 fail:

    close(fd);

    return -1;

}

AUDIT
int64_t qmp_guest_fsfreeze_thaw(Error **err)

{

    int ret;

    GuestFsfreezeMountList mounts;

    GuestFsfreezeMount *mount;

    int fd, i = 0, logged;



    QTAILQ_INIT(&mounts);

    ret = guest_fsfreeze_build_mount_list(&mounts);

    if (ret) {

        error_set(err, QERR_QGA_COMMAND_FAILED,

                  "failed to enumerate filesystems");

        return 0;

    }



    QTAILQ_FOREACH(mount, &mounts, next) {

        logged = false;

        fd = qemu_open(mount->dirname, O_RDONLY);

        if (fd == -1) {

            continue;

        }

        /* we have no way of knowing whether a filesystem was actually unfrozen

         * as a result of a successful call to FITHAW, only that if an error

         * was returned the filesystem was *not* unfrozen by that particular

         * call.

         *

         * since multiple preceeding FIFREEZEs require multiple calls to FITHAW

         * to unfreeze, continuing issuing FITHAW until an error is returned,

         * in which case either the filesystem is in an unfreezable state, or,

         * more likely, it was thawed previously (and remains so afterward).

         *

         * also, since the most recent successful call is the one that did

         * the actual unfreeze, we can use this to provide an accurate count

         * of the number of filesystems unfrozen by guest-fsfreeze-thaw, which

         * may * be useful for determining whether a filesystem was unfrozen

         * during the freeze/thaw phase by a process other than qemu-ga.

         */

        do {

            ret = ioctl(fd, FITHAW);

            if (ret == 0 && !logged) {

                i++;

                logged = true;

            }

        } while (ret == 0);

        close(fd);

    }



    guest_fsfreeze_state.status = GUEST_FSFREEZE_STATUS_THAWED;

    enable_logging();

    guest_fsfreeze_free_mount_list(&mounts);

    return i;

}

