static int run_ccw(struct subchannel_id schid, int cmd, void *ptr, int len)

{

    struct ccw1 ccw = {};

    struct cmd_orb orb = {};

    struct schib schib;

    int r;



    /* start command processing */

    stsch_err(schid, &schib);

    schib.scsw.ctrl = SCSW_FCTL_START_FUNC;

    msch(schid, &schib);



    /* start subchannel command */

    orb.fmt = 1;

