        r = asprintf(&p, "/dev/dri/%s", e->d_name);

        if (r < 0) {

            return -1;

        }



        r = open(p, O_RDWR | O_CLOEXEC | O_NOCTTY | O_NONBLOCK);

        if (r < 0) {

            free(p);

            continue;

        }

        fd = r;

        free(p);

        break;

    }



    closedir(dir);

    if (fd < 0) {

        return -1;

    }

    return fd;

}

